import{_ as a,o as r,c as o,ae as n}from"./chunks/framework.C8MNLDzb.js";const u=JSON.parse('{"title":"《韩非子》典故","description":"","frontmatter":{},"headers":[],"relativePath":"diangu/zi/韩非子.md","filePath":"diangu/zi/韩非子.md"}'),e={name:"diangu/zi/韩非子.md"};function s(i,t,g,l,d,h){return r(),o("div",null,[...t[0]||(t[0]=[n('<h1 id="《韩非子》典故" tabindex="-1">《韩非子》典故 <a class="header-anchor" href="#《韩非子》典故" aria-label="Permalink to &quot;《韩非子》典故&quot;">​</a></h1><h2 id="买椟还珠" tabindex="-1">买椟还珠 <a class="header-anchor" href="#买椟还珠" aria-label="Permalink to &quot;买椟还珠&quot;">​</a></h2><p><strong>典故：</strong> 楚国有个商人把珍珠装在漂亮的木匣子里到郑国去卖，郑国人买下木匣子，把珍珠还给了商人。 <strong>出处：</strong> 《韩非子·外储说左上》 <strong>释义：</strong> 比喻取舍失当，舍本逐末。</p><h2 id="守株待兔" tabindex="-1">守株待兔 <a class="header-anchor" href="#守株待兔" aria-label="Permalink to &quot;守株待兔&quot;">​</a></h2><p><strong>典故：</strong> 宋国有个农夫看见一只兔子撞死在树桩上，于是放下农具守着树桩，希望再得到兔子，结果再没有得到兔子，而他自己却被宋国人耻笑。 <strong>出处：</strong> 《韩非子·五蠹》 <strong>释义：</strong> 比喻死守狭隘经验，不知变通。</p><h2 id="滥竽充数" tabindex="-1">滥竽充数 <a class="header-anchor" href="#滥竽充数" aria-label="Permalink to &quot;滥竽充数&quot;">​</a></h2><p><strong>典故：</strong> 齐宣王喜欢听人吹竽，而且必须三百人一起吹。有个南郭先生根本不会吹竽，却混在乐队里装模作样。宣王死后，湣王即位，喜欢听一个人一个人地吹，南郭先生只好逃走了。 <strong>出处：</strong> 《韩非子·内储说上》 <strong>释义：</strong> 比喻没有真才实学的人混在行家里面充数。</p><h2 id="自相矛盾" tabindex="-1">自相矛盾 <a class="header-anchor" href="#自相矛盾" aria-label="Permalink to &quot;自相矛盾&quot;">​</a></h2><p><strong>典故：</strong> 楚国有个卖盾和矛的人，先夸他的盾最坚固，什么东西都刺不穿；又夸他的矛最锋利，什么东西都能刺穿。有人问：&quot;用你的矛刺你的盾会怎么样？&quot;那人答不上来。 <strong>出处：</strong> 《韩非子·难一》 <strong>释义：</strong> 比喻言语或行为前后互相抵触。</p><h2 id="刻舟求剑" tabindex="-1">刻舟求剑 <a class="header-anchor" href="#刻舟求剑" aria-label="Permalink to &quot;刻舟求剑&quot;">​</a></h2><p><strong>典故：</strong> 楚国有人坐船过江时，把剑掉在水里，他在船舷上刻了个记号，说：&quot;这里是我的剑掉下去的地方。&quot;等船靠岸后，他从刻记号的地方下水找剑。 <strong>出处：</strong> 《吕氏春秋·察今》 <strong>释义：</strong> 比喻拘泥成例，不知道跟着情势的变化而改变。</p>',11)])])}const _=a(e,[["render",s]]);export{u as __pageData,_ as default};
